<section class="container section"><div class="section-title"><h1>Mis reservaciones</h1><a class="btn small" href="index.php?route=reservation/create">Nueva</a></div><div class="table-wrap"><table><thead><tr><th>#</th><th>Hotel</th><th>Fechas</th><th>Personas</th><th>Total</th><th>Estado</th></tr></thead><tbody><?php foreach($reservations as $r):?><tr><td><?=$r['id']?></td><td><?=Security::e($r['hotel_name']??'Sin hotel')?></td><td><?=$r['check_in']?> al <?=$r['check_out']?></td><td><?=$r['people']?></td><td>₡<?=number_format($r['total'])?></td><td><span class="badge"><?=Security::e($r['status'])?></span></td></tr><?php endforeach;?></tbody></table></div></section>
